import React, { useState, useEffect } from 'react';
import { LogOut, User, BookOpen, Calendar, MapPin, Award, Bell, Search, ChevronDown, Briefcase, LayoutDashboard, Save, Loader2, CheckCircle, Plus, Trash2, Edit2, X, RefreshCw, Building2, ToggleLeft, ToggleRight, Clock, HelpCircle, FileText, Target, PieChart, TrendingUp, AlertCircle } from 'lucide-react';
import { Student } from '../types';
import EmploymentStatusPage from './EmploymentStatusPage';
import MyProfilePage from './MyProfilePage';
import { fetchLatestProfile } from '../services/resumeService';
import { supabase } from '../lib/supabaseClient';

interface DashboardProps {
  user: Student;
  onLogout: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ user, onLogout }) => {
  const [activeTab, setActiveTab] = useState<'home' | 'employment' | 'profile'>('home');
  const [loadingMetrics, setLoadingMetrics] = useState(true);

  // Dashboard Metrics State
  const [metrics, setMetrics] = useState({
    completionPercentage: 0,
    employmentStatus: 'Unknown',
    jobAlignment: 'N/A',
    latestCompany: '',
    missingSections: [] as string[]
  });

  useEffect(() => {
    const loadDashboardData = async () => {
        if (!user.id) return;
        setLoadingMetrics(true);
        try {
            const userType = user.enrollment_status === 'Graduating' ? 'graduating' : 'alumni';
            const table = userType === 'graduating' ? 'students' : 'alumni';

            // 1. Fetch Profile Data for Completion Calc
            const profileData = await fetchLatestProfile(user.id, userType);

            // 2. Fetch Latest Employment Record
            const idColumn = user.enrollment_status === 'Graduating' ? 'student_id' : 'alumni_id';
            const { data: surveys } = await supabase.from('survey_responses').select('id').eq(idColumn, user.id);

            // 3. Check for Resume Existence in DB
            const { data: resumeCheck } = await supabase
                .from(table)
                .select('id')
                .eq('id', user.id)
                .not('resume', 'is', null)
                .single();
            const hasResume = !!resumeCheck;

            let empStatus = 'Update Status';
            let alignment = 'N/A';
            let company = '';

            if (surveys && surveys.length > 0) {
                const surveyIds = surveys.map(s => s.id);
                const { data: records } = await supabase
                    .from('employment_information')
                    .select('*')
                    .in('survey_response_id', surveyIds)
                    .order('created_at', { ascending: false }) // Changed from id to created_at
                    .limit(1);

                if (records && records.length > 0) {
                    const latest = records[0];
                    empStatus = latest.employment_status || 'Unknown';
                    alignment = latest.job_alignment || 'N/A';
                    company = latest.company_name || latest.business_name || '';
                }
            }

            // 4. Calculate Completion Percentage
            let score = 0;
            const missing = [];

            // Base Info (From User Object) (20%)
            if (user.address && user.contact_no) score += 20;
            else missing.push("Contact Info");

            // Resume Uploaded (20%) - Uses fresh DB check
            if (hasResume) score += 20;
            else missing.push("Resume");

            if (profileData) {
                // Education (20%)
                if (profileData.education && (profileData.education.primary_school || profileData.education.bachelors_degree)) score += 20;
                else missing.push("Education");

                // Attributes Survey (20%)
                // Check if at least one attribute is rated > 0
                const hasAttributes = profileData.attributes && Object.values(profileData.attributes).some(val => Number(val) > 0);
                if (hasAttributes) score += 20;
                else missing.push("Graduate Attributes");

                // Employment History (20%)
                // Check if profile has employment array OR if we found a record in step 2
                if ((profileData.employment && profileData.employment.length > 0) || empStatus !== 'Update Status') score += 20;
                else missing.push("Employment History");
            } else {
                missing.push("Education", "Graduate Attributes", "Employment History");
            }

            setMetrics({
                completionPercentage: score,
                employmentStatus: empStatus,
                jobAlignment: alignment,
                latestCompany: company,
                missingSections: missing
            });

        } catch (error) {
            console.error("Dashboard Load Error", error);
        } finally {
            setLoadingMetrics(false);
        }
    };

    if (activeTab === 'home') {
        loadDashboardData();
    }
  }, [user.id, user.enrollment_status, activeTab]);

  // Helper component for arrows
  const ArrowRight = ({ size, className }: { size?: number, className?: string }) => (
    <svg 
      xmlns="http://www.w3.org/2000/svg" 
      width={size || 24} 
      height={size || 24} 
      viewBox="0 0 24 24" 
      fill="none" 
      stroke="currentColor" 
      strokeWidth="2" 
      strokeLinecap="round" 
      strokeLinejoin="round" 
      className={className}
    >
      <path d="M5 12h14"></path>
      <path d="m12 5 7 7-7 7"></path>
    </svg>
  );

  return (
    <div className="min-h-screen bg-gray-50/50 flex flex-col font-sans">

      {/* Background Pattern */}
      <div className="fixed inset-0 z-[-1] opacity-30" style={{ 
          backgroundImage: `radial-gradient(#e5e7eb 1px, transparent 1px)`,
          backgroundSize: '24px 24px' 
      }}></div>

      {/* Modern Header */}
      <header className="bg-white/80 backdrop-blur-xl border-b border-gray-200 sticky top-0 z-50 transition-all duration-300">
        <div className="container mx-auto px-4 lg:px-8 py-3">
          <div className="flex justify-between items-center">

            {/* Logo Area */}
            <div className="flex items-center space-x-3 group cursor-pointer" onClick={() => setActiveTab('home')}>
              <div className="w-10 h-10 bg-gradient-to-br from-luGreen to-luGreen-dark rounded-xl flex items-center justify-center shadow-lg group-hover:shadow-luGreen/30 transition-shadow">
                 <span className="text-white font-bold font-display text-lg">LU</span>
              </div>
              <div className="hidden md:block">
                <h1 className="text-lg font-bold text-gray-800 tracking-tight leading-none group-hover:text-luGreen transition-colors">ALUMNI TRACER</h1>
                <p className="text-[10px] text-gray-500 font-semibold tracking-widest uppercase mt-0.5">Laguna University</p>
              </div>
            </div>

            {/* Right Actions */}
            <div className="flex items-center space-x-3 md:space-x-6">

              <div className="hidden md:flex items-center space-x-2 text-xs bg-green-50 text-luGreen-dark py-1.5 px-3 rounded-full border border-green-100 shadow-sm">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-luGreen"></span>
                </span>
                <span className="font-medium">System Online</span>
              </div>

              <button className="p-2 text-gray-400 hover:text-luGold-dark hover:bg-yellow-50 rounded-full transition-all relative group">
                <Bell size={20} />
                <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
              </button>

              <div className="h-8 w-[1px] bg-gray-200 hidden md:block"></div>

              <button 
                onClick={onLogout}
                className="flex items-center space-x-2 bg-white hover:bg-gray-50 text-gray-600 hover:text-red-600 border border-gray-200 hover:border-red-100 transition-all py-2 px-4 rounded-xl text-sm font-medium shadow-sm hover:shadow-md active:scale-95"
              >
                <LogOut size={16} />
                <span className="hidden md:inline">Sign Out</span>
              </button>
            </div>
          </div>
