                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase">Business Address</label>
                                    <input required type="text" value={formData.business_address} onChange={e => handleInputChange('business_address', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" />
