                            </div>
                        </div>
                    )}

                    {formData.employment_status === 'Retired' && (
                        <div className="space-y-6">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase">Last Company</label>
                                    <input required type="text" value={formData.last_company} onChange={e => handleInputChange('last_company', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase">Date Retired</label>
                                    <input required type="date" value={formData.date_retired} onChange={e => handleInputChange('date_retired', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" />
                                </div>
                                <div className="col-span-1 md:col-span-2 space-y-2">
                                    <label className="text-xs font-bold text-gray-500 uppercase">Retirement Reason</label>
                                    <textarea required rows={2} value={formData.retirement_reason} onChange={e => handleInputChange('retirement_reason', e.target.value)} className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-200 focus:border-luGreen focus:outline-none" />
                                </div>
                            </div>
                        </div>
                    )}

                    <div className="pt-6 border-t border-gray-100 flex gap-4">
                        <button 
                            type="submit" 
                            disabled={submitting}
                            className="flex-1 px-8 py-3 bg-luGreen text-white font-bold rounded-xl shadow-lg hover:bg-luGreen-dark hover:shadow-xl transition-all flex items-center justify-center gap-2"
                        >
                            {submitting ? (
                                <>
                                    <Loader2 className="animate-spin w-5 h-5" />
                                    <span>Processing...</span>
                                </>
                            ) : (
                                <>
                                    <Save size={20} />
                                    <span>Save Record</span>
                                </>
                            )}
                        </button>
                            <button 
                            type="button" 
                            onClick={cancelForm}
                            className="px-6 py-3 bg-white border border-gray-200 text-gray-600 font-bold rounded-xl hover:bg-gray-50 transition-all"
                        >
                            Cancel
                        </button>
                    </div>
                </form>
            )}
        </div>
    </div>

    {/* === TRANSITION CONFIRMATION MODAL === */}
    {showTransitionModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-gray-900/40 backdrop-blur-md animate-in fade-in duration-300" onClick={() => !processingTransition && setShowTransitionModal(false)}></div>
            <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-md relative z-10 overflow-hidden animate-in zoom-in-95 duration-300 border border-white/20">
                <div className="p-8 text-center">
                    <div className="w-16 h-16 bg-amber-50 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner ring-4 ring-amber-50/50">
                        <AlertTriangle className="w-8 h-8 text-amber-500" />
                    </div>
                    <h3 className="text-2xl font-black text-gray-800 mb-2">Change Job Status?</h3>
                    <div className="text-gray-500 text-sm mb-8 leading-relaxed space-y-2">
                        <p>Are you sure you want to change your status to <strong className="text-gray-800">{pendingStatus}</strong>?</p>
                        <p className="text-xs bg-gray-50 p-3 rounded-lg border border-gray-100">
                            Your current active employment records will be moved to your <span className="font-bold">Employment History</span> (Profile) and will no longer be counted as active in the system.
                        </p>
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                         <button 
                            onClick={() => setShowTransitionModal(false)}
                            disabled={processingTransition}
                            className="py-3.5 bg-gray-100 hover:bg-gray-200 text-gray-700 font-bold rounded-xl transition-colors text-sm"
                        >
                            Cancel
                        </button>
                        <button 
                            onClick={executeStatusTransition}
                            disabled={processingTransition}
                            className="py-3.5 bg-luGreen hover:bg-luGreen-dark text-white font-bold rounded-xl shadow-lg shadow-green-200 transition-all text-sm flex items-center justify-center gap-2"
                        >
                            {processingTransition ? <Loader2 size={16} className="animate-spin" /> : "Yes, Confirm"}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    )}
    </>
  );
};

