export const fetchLatestProfile = async (userId: string, userType: 'graduating' | 'alumni' | 'student'): Promise<FullProfileData | null> => {
    const idColumn = userType === 'graduating' ? 'student_id' : 'alumni_id';

    // 1. Get ALL survey responses IDs for this user to fetch full cumulative history
    const { data: allSurveys, error: surveyError } = await supabase
        .from('survey_responses')
        .select('id, submitted_at')
        .eq(idColumn, userId)
        .order('submitted_at', { ascending: false });

    if (surveyError || !allSurveys || allSurveys.length === 0) {
        return null; // No profile data saved yet
    }

    const latestSurveyId = allSurveys[0].id; // For snapshot data (Education, Attributes)
    const allSurveyIds = allSurveys.map(s => s.id); // For cumulative data (Employment History)

    // 2. Fetch related data in parallel
    const [education, employment, community, attributes] = await Promise.all([
        supabase.from('education_information').select('*').eq('survey_response_id', latestSurveyId).single(),
        supabase.from('employment_history').select('*').in('survey_response_id', allSurveyIds).order('date_hired', { ascending: false }),
        supabase.from('community_engagement').select('*').eq('survey_response_id', latestSurveyId),
        supabase.from('alumni_attributes').select('*').eq('survey_response_id', latestSurveyId).single()
    ]);

    return {
        education: education.data || {},
        employment: employment.data || [],
        community: community.data || [],
        attributes: attributes.data || {
            professionally_competent: 0,
            critical_thinker: 0,
            communicator: 0,
            lifelong_learner: 0,
            socially_responsible: 0,
            ethical_citizen: 0,
            innovative_worker: 0,
            people_oriented: 0,
            critical_thinking_skill: 0,
            creativity: 0,
            collaboration: 0,
            communication_skill: 0,
            information_literacy: 0,
            media_literacy: 0,
            technology_literacy: 0,
            flexibility: 0,
            leadership: 0,
            initiative: 0,
            productivity: 0,
            social_skills: 0
        }
    };
};

